using System;
using System.Collections.Generic;
using System.Xml;

public class ConfigParser
{
    public Dictionary<string, string> ParseConfig(string filePath)
    {
        XmlDocument xmlDoc = new XmlDocument();
        try
        {
            xmlDoc.Load(filePath);
        }
        catch (XmlException e)
        {
            Console.WriteLine($"Error loading XML file: {e.Message}");
            return null;
        }

        Dictionary<string, string> settings = new Dictionary<string, string>();

        foreach (XmlNode node in xmlDoc.DocumentElement.ChildNodes)
        {
            if (node.NodeType == XmlNodeType.Element)
            {
                settings.Add(node.Name, node.InnerText);
            }
        }

        // Handle external DTD references
        foreach (XmlAttribute attr in xmlDoc.DocumentElement.Attributes)
        {
            if (attr.Name.StartsWith("DOCTYPE") && !string.IsNullOrEmpty(attr.Value))
            {
                string[] lines = attr.Value.Split(new char[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries);
                foreach (string line in lines)
                {
                    if (line.StartsWith("<![CDATA[")) // Ignore internal DOCTYPE declarations
                    {
                        continue;
                    }
                    else if (line.StartsWith("<!ENTITY")) // Ignore external entity definitions
                    {
                        continue;
                    }
                    else
                    {
                        string[] parts = line.Split(new char[] { ' ', '=' }, StringSplitOptions.RemoveEmptyEntries);
                        if (parts.Length == 2)
                        {
                            settings.Add(parts[0], parts[1]);
                        }
                    }
                }
            }
        }

        return settings;
    }
}